% MATLAB equivalent for minimum distance demapping
rx_reshaped = rx(:); % Column vector
const_reshaped = constellation(:).'; % Row vector
distances = abs(rx_reshaped - const_reshaped).^2;
[~, min_indices] = min(distances, [], 2);
demapped = constellation(min_indices);

